    func createAgent() throws -> (EdgeAgent, MockPluto) {
        let apollo = ApolloImpl()
        let castor = CastorImpl(apollo: apollo)
        let pluto = MockPluto()
        let pollux = MockPollux()
        let seed = seed
        let agent = EdgeAgent(
            apollo: apollo,
            castor: castor,
            pluto: pluto,
            pollux: pollux,
            seed: { seed }
        )
        return (agent, pluto)
    }

    func createAgentWitouthMocks() throws -> (EdgeAgent, Pluto) {
        let apollo = ApolloImpl()
        let castor = CastorImpl(apollo: apollo)
        let pluto = PlutoImpl(setup: .init(coreDataSetup: .init(modelPath: .storeName("PrismPluto"), storeType: .memory), keychain: KeychainMock()))
        let pollux = PolluxImpl(castor: castor, pluto: pluto)
        let seed = seed
        let agent = EdgeAgent(
            apollo: apollo,
            castor: castor,
            pluto: pluto,
            pollux: pollux,
            seed: { seed }
        )
        return (agent, pluto)
    }

    private func decodeBackup(encrypted: String, seed: Seed, apollo: Apollo & KeyRestoration) throws -> EdgeAgent.Backup {
        let masterKey = try apollo.createPrivateKey(parameters: [
            KeyProperties.type.rawValue: "EC",
            KeyProperties.curve.rawValue: KnownKeyCurves.x25519.rawValue,
            KeyProperties.seed.rawValue: seed.value.base64Encoded(),
            KeyProperties.derivationPath.rawValue: DerivationPath().keyPathString()
        ])

        guard let exporting = masterKey.exporting else {
            throw EdgeAgentError.keyIsNotExportable
        }

        let jwk = try JSONEncoder.didComm().encode(exporting.jwk)
        let backupData = try JWE(compactString: encrypted)
            .decrypt(recipientKey: try JSONDecoder.didComm().decode(JSONWebKey.JWK.self, from: jwk))
        return try JSONDecoder.didComm().decode(EdgeAgent.Backup.self, from: backupData)
    }

    private func summarizeBackupMessages(_ messages: [String]) -> [String] {
        return messages.compactMap { messageStr in
            guard let messageData = Data(base64URLEncoded: messageStr) else {
                return "decode-failed|invalid-base64"
            }
            if let message = try? JSONDecoder.backup().decode(Message.self, from: messageData) {
                return "\(message.id)|\(message.piuri)|\(message.thid ?? "nil")"
            }
            if
                let obj = try? JSONSerialization.jsonObject(with: messageData) as? [String: Any]
            {
                let id = (obj["id"] as? String) ?? "unknown-id"
                let piuri = (obj["type"] as? String) ?? (obj["piuri"] as? String) ?? "unknown-type"
                let thid = (obj["thid"] as? String) ?? "nil"
                let summary = summarizeBackupMessageJSON(obj)
                return "\(id)|\(piuri)|\(thid)|decode-failed|\(summary)"
            }
            return "decode-failed|unknown"
        }
    }

    private func summarizeBackupMessageJSON(_ obj: [String: Any]) -> String {
        func firstValue(_ keys: [String]) -> Any? {
            for key in keys {
                if let value = obj[key] {
                    return value
                }
            }
            return nil
        }

        func describe(_ value: Any?) -> String {
            guard let value else { return "missing" }
            if value is NSNull { return "null" }
            if value is String { return "string" }
            if value is NSNumber { return "number" }
            if value is Bool { return "bool" }
            if let array = value as? [Any] { return "array(count=\(array.count))" }
            if let dict = value as? [String: Any] { return "object(keys=\(dict.keys.sorted()))" }
            return "unknown(\(type(of: value)))"
        }

        let from = firstValue(["from"])
        let to = firstValue(["to"])
        let fromPrior = firstValue(["from_prior", "fromPrior"])
        let body = firstValue(["body"])
        let extraHeaders = firstValue(["extra_headers", "extraHeaders"])
        let createdTime = firstValue(["created_time", "createdTime"])
        let expiresTime = firstValue(["expires_time_plus", "expiresTimePlus", "expiresTime"])
        let attachments = firstValue(["attachments"])
        let ack = firstValue(["ack"])
        let direction = firstValue(["direction"])

        var parts: [String] = []
        parts.append("from=\(describe(from))")
        parts.append("to=\(describe(to))")
        parts.append("fromPrior=\(describe(fromPrior))")
        parts.append("body=\(describe(body))")
        parts.append("extraHeaders=\(describe(extraHeaders))")
        parts.append("createdTime=\(describe(createdTime))")
        parts.append("expiresTime=\(describe(expiresTime))")
        parts.append("attachments=\(describe(attachments))")
        parts.append("ack=\(describe(ack))")
        parts.append("direction=\(describe(direction))")

        if let bodyDict = body as? [String: Any] {
            parts.append("bodyKeys=\(bodyDict.keys.sorted())")
        }

        if let attachmentsArray = attachments as? [Any], let first = attachmentsArray.first as? [String: Any] {
            parts.append("firstAttachmentKeys=\(first.keys.sorted())")
        }

        if let createdTimeValue = createdTime {
            parts.append("createdTimeValue=\(String(describing: createdTimeValue))")
        }
        if let expiresTimeValue = expiresTime {
            parts.append("expiresTimeValue=\(String(describing: expiresTimeValue))")
        }
        if let directionValue = direction {
            parts.append("directionValue=\(String(describing: directionValue))")
        }

        return parts.joined(separator: ", ")
    }

    func testBackup() async throws {
        let (backupAgent, backupPluto) = try createAgent()
        _ = try await backupAgent.createNewPrismDID(masterPrivateKey: nil)
        _ = try await backupAgent.createNewPrismDID(masterPrivateKey: nil)

        backupPluto.didPairs = [
            .init(
                holder: .init(method: "peer", methodId: "alice"),
                other: .init(method: "peer", methodId: "bob"),
                name: "test"
            )
        ]

        let mockedCredential = MockCredential(exporting: Data(count: 10), restorationType: "mock")
        backupPluto.credentials = [mockedCredential]

        backupPluto.messages = [Message(piuri: "mock", body: Data(count: 20))]
        backupPluto.mediators = [(.init(method: "peer", methodId: "holder"), .init(method: "peer", methodId: "mediator"),.init(method: "peer", methodId: "routing"))]
        backupPluto.linkSecret = try ApolloImpl().createNewLinkSecret().storable!

        let str = try await backupAgent.backupWallet()
        let (receivingAgent, receivingPluto) = try createAgent()
        try await receivingAgent.recoverWallet(encrypted: str)

        XCTAssertEqual(backupPluto.dids.count, receivingPluto.dids.count)
        XCTAssertEqual(backupPluto.credentials.count, receivingPluto.credentials.count)
        XCTAssertEqual(backupPluto.didPairs.count, receivingPluto.didPairs.count)
        XCTAssertEqual(backupPluto.messages.count, receivingPluto.messages.count)
        XCTAssertEqual(backupPluto.mediators.count, receivingPluto.mediators.count)
        XCTAssertNotNil(receivingPluto.linkSecret)
    }

    func testInteroperabilityTSSDK() async throws {
        let (receivingAgent, receivingPluto) = try createAgentWitouthMocks()
        try await receivingAgent.recoverWallet(encrypted: tsJweString)
        let keys = try await receivingPluto.getAllKeys().first().await().count
        let mediators = try await receivingPluto.getAllMediators().first().await().count
        let credentials = try await receivingPluto.getAllCredentials().first().await().count
        let dids = try await receivingPluto.getAllDIDs().first().await().count
        let didPairs = try await receivingPluto.getAllDidPairs().first().await().count
        let messages = try await receivingPluto.getAllMessages().first().await().count
        let linkSecret = try await receivingPluto.getLinkSecret().first().await()
        XCTAssertEqual(keys, 2)
        XCTAssertEqual(mediators, 1)
        XCTAssertEqual(credentials, 2)
        XCTAssertEqual(dids, 2)
        XCTAssertEqual(didPairs, 1)
        XCTAssertEqual(messages, 1)
        XCTAssertNotNil(linkSecret)
    }

    func testInteroperabilityKotlinSDK() async throws {
        let (receivingAgent, receivingPluto) = try createAgentWitouthMocks()
        let backup = try decodeBackup(encrypted: kmpJweBackup, seed: seed, apollo: receivingAgent.apollo)
        let backupMessageSummaries = summarizeBackupMessages(backup.messages)
        try await receivingAgent.recoverWallet(encrypted: kmpJweBackup)
        let keys = try await receivingPluto.getAllKeys().first().await().count
        let mediators = try await receivingPluto.getAllMediators().first().await().count
        let credentials = try await receivingPluto.getAllCredentials().first().await().count
        let dids = try await receivingPluto.getAllDIDs().first().await().count
        let didPairs = try await receivingPluto.getAllDidPairs().first().await().count
        let restoredMessages = try await receivingPluto.getAllMessages().first().await()
        let restoredMessageSummaries = restoredMessages.map { "\($0.id)|\($0.piuri)|\($0.thid ?? "nil")" }
        let messages = restoredMessages.count
        let linkSecret = try await receivingPluto.getLinkSecret().first().await()
        XCTAssertEqual(keys, 17) //  TODO: +1 due linkSecret key
        XCTAssertEqual(mediators, 1)
        XCTAssertEqual(credentials, 3)
        XCTAssertEqual(dids, 9)
        XCTAssertEqual(didPairs, 1)
        XCTAssertEqual(messages, 15)
        XCTAssertNotNil(linkSecret)
    }
